DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "流量越来越贵 / 投放 ROI 持续下滑"
  "私域转化率低 / 用户反感 / 被屏蔽删好友"
  "要选私域承接的主战场 / 现有个人号矩阵要不要迁"
  "私域 ROI 不行"
  "要判断「私域值不值得做」"
  "面对「要不要一次性把全套做全 / 做大 / 做完美」"
  "选私域工具"
)
declare -a RULE_ACTIONS=(
  "先问「这部分流量能不能沉淀成可反复免费触达的私域」，而不是继续加投放预算——把「买一次用一次」换成「买一次反复用」是私域存在的理由"
  "先查「是不是全员一套话术」，按标签 + 生命周期分层是精细化的第一刀；且标签体系要反推自「我要做哪些差异化动作」——没有触达策略对应的标签是死标签"
  "默认企业微信为主战场、个人号为辅助——2024 起已成定局；任何「个人号无脑加好友 / 多开矩阵」式建议直接判过时（撞封号红线、客户不可继承）"
  "不要笼统归因，按「引流 → 沉淀 → 触达 → 转化 → 复购 → 裂变」逐环看转化率，定位漏损最大的一环——尤其先查「承接」（引流和承接是两段，引来 1000 个、加好友通过率 30%、破冰留存 50%，实际只剩 150，承接漏损往往比引流本身更致命）"
  "用 LTV / 复购视角而非首单 ROI 评判（私域经济模型是「首购可能亏、复购才赚」），且先过品类适配性 + 三个前置条件——品类高复购 / 高客单 / 决策链长才适合；稳定公域流量来源、能持续产内容的人、客单价能覆盖私域人力成本，三者缺一就先补前置条件、不硬启动"
  "默认先用最小版本验证跑通再放大——0→1 阶段先用「企微 1v1 + 朋友圈」两件套验证品类和话术，跑通了再加触点 / 加渠道 / 加标签维度 / 做归因体系。私域最大的死法不是做得不够，是摊子铺太大、每个都半成品"
  "先过合规门槛（合规资质齐全 + 会话存档能力）再看别的，不看低价、不看功能数量——没有齐全合规资质的产品再便宜也是监管风险；反向信号：对续费率自信的厂商不会自降身价推「多年使用权 + 打折」，看到这种促销要警惕"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
